import { useNavigate } from "react-router-dom";
import { useState, useEffect } from "react";
import api from "../api/axios";
import "./styles/Books.css";

function AddBook() {
  const navigate = useNavigate();
  const genre = localStorage.getItem("genre");
  const role = localStorage.getItem("role");

  const [title, setTitle] = useState("");
  const [author, setAuthor] = useState("");
  const [imageURL, setImageURL] = useState("");
  const [about, setAbout] = useState("");
  const [authorInfo, setAuthorInfo] = useState("");
  const [message, setMessage] = useState("");

  // 🔐 Security check
  useEffect(() => {
    if (role !== "Librarian" || !genre) {
      navigate("/login", { replace: true });
    }
  }, [role, genre, navigate]);

  const handleAddBook = async () => {
    try {
      if (!title || !author || !imageURL || !about || !authorInfo) {
        return setMessage("Please fill all fields");
      }

      await api.post("/books/add", {
        title,
        author,
        imageURL,
        about,
        authorInfo,
        genre // 🔥 automatically uses librarian genre
      });

      setMessage("Book added successfully!");

      // Clear fields
      setTitle("");
      setAuthor("");
      setImageURL("");
      setAbout("");
      setAuthorInfo("");

    } catch (err) {
      setMessage(err.response?.data?.message || "Error adding book");
    }
  };

  return (
    <div className="books-page">
      <h1 className="books-title">
        Add New <span className="highlight-genre">{genre}</span> Book
      </h1>

      <div className="detail-card">

        <input
          placeholder="Book Title"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
        />

        <input
          placeholder="Author"
          value={author}
          onChange={(e) => setAuthor(e.target.value)}
        />

        <input
          placeholder="Cover Image URL"
          value={imageURL}
          onChange={(e) => setImageURL(e.target.value)}
        />

        <textarea
          placeholder="About the Book"
          value={about}
          onChange={(e) => setAbout(e.target.value)}
        />

        <textarea
          placeholder="About the Author"
          value={authorInfo}
          onChange={(e) => setAuthorInfo(e.target.value)}
        />

        {/* 🔥 Show genre (read-only) */}
        <input value={genre} disabled />

        <button className="borrow-btn" onClick={handleAddBook}>
          Add Book
        </button>

        {message && <p style={{ marginTop: "12px" }}>{message}</p>}
      </div>
    </div>
  );
}

export default AddBook;
